(function(window2, document2) {
  var button1 = document2.getElementById("button1");
  var button2 = document2.getElementById("button2");
  var button3 = document2.getElementById("button3");
  var setCommand = function(button, command) {
    button.onclick = function() {
      command.execute();
    };
  };
  var MenuBar = {
    refresh: function() {
      console.log("刷新菜单目录");
    }
  };
  var SubMenu = {
    add: function() {
      console.log("增加子菜单");
    },
    del: function() {
      console.log("删除子菜单");
    }
  };
  var RefreshMenuBarCommand = function(receiver) {
    this.receiver = receiver;
  };
  RefreshMenuBarCommand.prototype.execute = function() {
    this.receiver.refresh();
  };
  var AddSubMenuCommand = function(receiver) {
    this.receiver = receiver;
  };
  AddSubMenuCommand.prototype.execute = function() {
    this.receiver.add();
  };
  var DelSubMenuCommand = function(receiver) {
    this.receiver = receiver;
  };
  DelSubMenuCommand.prototype.execute = function() {
    this.receiver.del();
  };
  var refreshMenuBarCommand = new RefreshMenuBarCommand(MenuBar);
  var addSubMenuCommand = new AddSubMenuCommand(SubMenu);
  var delSubMenuCommand = new DelSubMenuCommand(SubMenu);
  setCommand(button1, refreshMenuBarCommand);
  setCommand(button2, addSubMenuCommand);
  setCommand(button3, delSubMenuCommand);
  var Ryu = {
    attack: function() {
      console.log("攻击");
    },
    defense: function() {
      console.log("防御");
    },
    jump: function() {
      console.log("跳跃");
    },
    crouch: function() {
      console.log("蹲下");
    }
  };
  var makeCommand = function(receiver, state) {
    return function() {
      receiver[state]();
    };
  };
  var commands = {
    "119": "jump",
    // W
    "115": "crouch",
    // S
    "97": "defense",
    // A
    "100": "attack"
    // D
  };
  var commandStack = [];
  document2.onkeypress = function(event) {
    var keyCode = event.keyCode;
    if (keyCode !== 119 && keyCode !== 115 && keyCode !== 97 && keyCode !== 100) {
      return;
    }
    var command = makeCommand(Ryu, commands[keyCode]);
    if (command) {
      command();
      commandStack.push(command);
    }
  };
  document2.getElementById("replay").onclick = function() {
    var command;
    while (command = commandStack.shift()) {
      command();
    }
  };
  var closeDoorCommand = {
    execute: function() {
      console.log("关门");
    }
  };
  var openPcCommand = {
    execute: function() {
      console.log("开电脑");
    }
  };
  var openQQCommand = {
    execute: function() {
      console.log("登录QQ");
    }
  };
  var MacroCommand = function() {
    return {
      commandsList: [],
      add: function(command) {
        this.commandsList.push(command);
      },
      execute: function() {
        for (var i = 0, command; command = this.commandsList[i++]; ) {
          command.execute();
        }
      }
    };
  };
  var macroCommand = MacroCommand();
  macroCommand.add(closeDoorCommand);
  macroCommand.add(openPcCommand);
  macroCommand.add(openQQCommand);
  macroCommand.execute();
})(window, document);
